class Solution:
    def leastBricks(self, wall: List[List[int]]) -> int:
        from collections import Counter
        cnt = Counter()
        for row in wall:
            s = 0
            for b in row[:-1]:
                s += b
                cnt[s] += 1
        if not cnt:
            return len(wall)
        return len(wall) - cnt.most_common(1)[0][1]

