class Solution {
public:
    int leastBricks(vector<vector<int>>& wall) {
        unordered_map<int,int> cnt;
        for (auto& row : wall) {
            int s = 0;
            for (int i = 0; i + 1 < (int)row.size(); i++) {
                s += row[i];
                cnt[s]++;
            }
        }
        int best = 0;
        for (auto& p : cnt) best = max(best, p.second);
        return wall.size() - best;
    }
};
